vector&lt;int&gt; dp0, dp1;

void dfs(int v, int p) {
    dp1[v] = 1;  // choose v
    dp0[v] = 0;  // don't choose v

    for (int to : g[v]) {
        if (to == p) continue;
        dfs(to, v);

        // if we choose v, we must NOT choose child
        dp1[v] += dp0[to];

        // if we don't choose v, child can be either
        dp0[v] += max(dp0[to], dp1[to]);
    }
}
